from typing import List, Tuple, Dict
import heapq


def a_star_search(
    grid: List[List[int]],
    start: Tuple[int, int],
    goal: Tuple[int, int]
) -> List[Tuple[int, int]]:
    rows, cols = len(grid), len(grid[0])
    if not grid or not grid[0]:
        return []
    if grid[start[0]][start[1]] == 1 or grid[goal[0]][goal[1]] == 1:
        return []

    def heuristic(a: Tuple[int, int], b: Tuple[int, int]) -> int:
        return abs(a[0] - b[0]) + abs(a[1] - b[1])

    open_set = [(0, start)]
    came_from: Dict[Tuple[int, int], Tuple[int, int]] = {}
    g_score: Dict[Tuple[int, int], float] = {start: 0}
    f_score: Dict[Tuple[int, int], float] = {start: heuristic(start, goal)}

    while open_set:
        _, current = heapq.heappop(open_set)

        if current == goal:
            path = []
            while current in came_from:
                path.append(current)
                current = came_from[current]
            path.append(start)
            return path[::-1]

        r, c = current
        for dr, dc in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
            nr, nc = r + dr, c + dc
            neighbor = (nr, nc)
            if 0 <= nr < rows and 0 <= nc < cols and grid[nr][nc] == 0:
                tentative_g = g_score[current] + 1
                if tentative_g < g_score.get(neighbor, float('inf')):
                    came_from[neighbor] = current
                    g_score[neighbor] = tentative_g
                    f = tentative_g + heuristic(neighbor, goal)
                    f_score[neighbor] = f
                    heapq.heappush(open_set, (f, neighbor))

    return []

import threading
from typing import Optional, Any
from collections import deque


class BoundedQueue:

    def __init__(self, maxsize: int) -> None:
        if maxsize <= 0:
            raise ValueError("maxsize must be positive")
        self.maxsize = maxsize
        self.queue: deque = deque()
        self.mutex = threading.Lock()
        self.not_full = threading.Condition(self.mutex)
        self.not_empty = threading.Condition(self.mutex)

    def put(self, item: Any) -> None:
        with self.not_full:
            while len(self.queue) >= self.maxsize:
                self.not_full.wait()
            self.queue.append(item)
            self.not_empty.notify()

    def get(self) -> Any:
        with self.not_empty:
            while len(self.queue) == 0:
                self.not_empty.wait()
            item = self.queue.popleft()
            self.not_full.notify()
            return item

    def qsize(self) -> int:
        with self.mutex:
            return len(self.queue)

from typing import Optional, List
from collections import deque


def serialize(root: Optional[TreeNode]) -> str:
    if not root:
        return ""

    result: List[str] = []
    queue = deque([root])

    while queue:
        node = queue.popleft()
        if node:
            result.append(str(node.val))
            queue.append(node.left)
            queue.append(node.right)
        else:
            result.append("null")

    # Strip trailing nulls
    while result and result[-1] == "null":
        result.pop()

    return ",".join(result)


def deserialize(data: str) -> Optional[TreeNode]:
    if not data:
        return None

    values = data.split(",")
    if values[0] == "null":
        return None

    root = TreeNode(int(values[0]))
    queue = deque([root])
    i = 1

    while queue and i < len(values):
        node = queue.popleft()

        if i < len(values) and values[i] != "null":
            node.left = TreeNode(int(values[i]))
            queue.append(node.left)
        i += 1

        if i < len(values) and values[i] != "null":
            node.right = TreeNode(int(values[i]))
            queue.append(node.right)
        i += 1

    return root

from typing import Tuple
from functools import lru_cache


def regex_match(text: str, pattern: str) -> bool:

    @lru_cache(maxsize=None)
    def dp(i: int, j: int) -> bool:
        # Base case: both exhausted
        if j == len(pattern):
            return i == len(text)

        # Check if current characters match (first char match)
        first_match = i < len(text) and (pattern[j] == text[i] or pattern[j] == '.')

        # Handle '*' -- zero or more of preceding element
        if j + 1 < len(pattern) and pattern[j + 1] == '*':
            # Zero occurrences: skip pattern[j] and pattern[j+1] ('*')
            # One or more: consume text[i] if first_match, stay on same pattern
            return dp(i, j + 2) or (first_match and dp(i + 1, j))
        else:
            # No '*' — must match current character
            return first_match and dp(i + 1, j + 1)

    return dp(0, 0)
